# combine multiple tables from the same statement, one company (eg:si1, si2 -> si)

import os
import json
import re
import shutil

# --- Configuration ---
# Input directory: Contains company folders and JSON files generated by the previous script.
INPUT_DIR = "raw_table_data_v2"
# Output directory: Where the merged and processed files will be stored.
OUTPUT_DIR = "multiple_combined_table_v2"
# --- End Configuration ---

def merge_table_files(file_list, output_filepath):
    """
    Merges the content of multiple table JSON files.
    It takes the entire content of the first file as a base,
    and appends the content from subsequent files that comes after the '[Time]:' tag.

    Args:
        file_list (list): A sorted list of source file paths to be merged.
        output_filepath (str): The destination file path for the merged content.
    """
    if not file_list:
        return

    try:
        with open(file_list[0], 'r', encoding='utf-8') as f:
            # JSON content is ["..."], so we take the first element.
            merged_content = json.load(f)[0]
    except (IOError, json.JSONDecodeError, IndexError) as e:
        print(f"    -> ERROR: Failed to read or parse base file {os.path.basename(file_list[0])}: {e}")
        return

    for filepath in file_list[1:]:
        try:
            with open(filepath, 'r', encoding='utf-8') as f:

                
                content = json.load(f)[0]
                time_marker = '[Time]:'
                time_pos = content.find(time_marker)

                if time_pos != -1:
                    # Append content from the '[Time]:' marker onwards.
                    merged_content += "\n" + content[time_pos:]
                else:
                    # Warn if the marker is not found to avoid corrupting the format.
                    print(f"    -> WARNING: Marker '{time_marker}' not found in {os.path.basename(filepath)}. Skipping file.")

        except (IOError, json.JSONDecodeError, IndexError) as e:
            print(f"    -> ERROR: Failed to read or parse additional file {os.path.basename(filepath)}: {e}")
            continue # Continue with the next file.

    try:
        with open(output_filepath, 'w', encoding='utf-8') as f:
            # Store the merged content in the same list format.
            json.dump([merged_content], f, ensure_ascii=False, indent=4)
    except IOError as e:
        print(f"    -> ERROR: Failed to write merged file {os.path.basename(output_filepath)}: {e}")


if __name__ == "__main__":
    script_dir = os.path.dirname(os.path.abspath(__file__))
    root_input_dir = os.path.join(script_dir, INPUT_DIR)
    root_output_dir = os.path.join(script_dir, OUTPUT_DIR)

    if not os.path.exists(root_input_dir) or not os.path.isdir(root_input_dir):
        print(f"Error: Input directory '{root_input_dir}' not found.")
    else:
        print(f"Input Directory:  {root_input_dir}")
        print(f"Output Directory: {root_output_dir}\n")
        os.makedirs(root_output_dir, exist_ok=True)

        for company_name in os.listdir(root_input_dir):
            company_input_path = os.path.join(root_input_dir, company_name)

            if os.path.isdir(company_input_path):
                print(f"Processing Company: {company_name}")
                company_output_path = os.path.join(root_output_dir, company_name)
                os.makedirs(company_output_path, exist_ok=True)

                files_to_process = {}
                for filename in os.listdir(company_input_path):
                    if filename.endswith('.json'):
                        # Use regex to extract the base name (e.g., "bs" from "bs1.json").
                        match = re.match(r'([a-zA-Z_]+)', filename)
                        if match:
                            base_name = match.group(1)
                            if base_name not in files_to_process:
                                files_to_process[base_name] = []
                            files_to_process[base_name].append(os.path.join(company_input_path, filename))

                for base_name, file_list in files_to_process.items():
                    # Sort the file list to ensure correct order (e.g., bs1 before bs2).
                    file_list.sort()
                    output_filename = f"{base_name}.json"
                    output_filepath = os.path.join(company_output_path, output_filename)

                    if len(file_list) > 1:
                        # If there's more than one file, merge them.
                        print(f"  -> Merging {len(file_list)} '{base_name}' files -> {output_filename}")
                        merge_table_files(file_list, output_filepath)
                    elif len(file_list) == 1:
                        # If there's only one file, just copy it.
                        print(f"  -> Copying '{base_name}.json'")
                        shutil.copy2(file_list[0], output_filepath)

                print("-" * 30)